// Rango real ADC MQ-135: 0–1023
// Zona normal CO2/VOC interior: 300–700
var base = 450;
var ruido = Math.floor(Math.random() * 400) - 200;
var valor = Math.max(0, Math.min(1023, base + ruido));
msg.payload = String(valor);
return msg;

var valor = parseFloat(msg.payload);
if (isNaN(valor)) {
    node.warn('Payload no numérico: ' + msg.payload);
    return null;
}
msg.payload = { value: valor };
return msg;

var err = msg.error || {};
var texto = '❌ ERROR InfluxDB\n';
texto += 'Mensaje : ' + (err.message || 'desconocido') + '\n';
texto += 'Nodo    : ' + (err.source ? err.source.name : 'N/A');

if ((err.message || '').toLowerCase().includes('bucket')) {
    texto += '\n💡 Bucket no encontrado. Ejecute:\n'
           + 'docker exec -it ming_influxdb influx bucket create --name gas_data --org myorg --token ming-token --retention 0';
} else if ((err.message || '').match(/unauthorized|401/i)) {
    texto += '\n💡 Token inválido. Verifique en Configuration nodes → InfluxDB Local → Token: ming-token';
} else if ((err.message || '').match(/ECONNREFUSED|ENOTFOUND/i)) {
    texto += '\n💡 Contenedor no alcanzable. Verifique:\n'
           + 'docker ps | grep influxdb';
} else if ((err.message || '').match(/credential|secret|encrypt/i)) {
    texto += '\n💡 Credenciales corruptas. Ejecute:\n'
           + 'docker exec ming_nodered rm -f /data/flows_cred.json\n'
           + 'docker restart ming_nodered\n'
           + 'Luego configure el token en Configuration nodes → InfluxDB Local';
}

msg.payload = texto;
return msg;
